// ============================================
// ANTI-DUPLICADOS - Z.ai Implementation
// Posicionarse en la hoja de control y verificar
// que el tema no existe ya con estado PENDIENTE o EN_PROCESO
// ============================================

const SPREADSHEET_ID = '2772493032989228627'; // Blog ID de Luis
const SHEET_NAME = 'Control_Publicaciones';
const HOJA_RANGO = 'A2:L1000';

// Generar ID unico del tema
const topic = $json.topic || $json.tema || $json.titulo || 'sin-tema';
const flowName = $workflow.name || 'unknown';
const bloque = '1'; // Se actualiza segun el bloque activo
const fecha = new Date().toISOString().slice(0, 10);
const topicHash = topic.substring(0, 50).replace(/[^a-zA-Z0-9]/g, '_').toLowerCase();
const idTema = `${bloque}_${flowName.replace(/\s+/g, '_')}_${fecha}_${topicHash}`;

// Agregar metadata al item
$json._anti_dup = {
  id_tema: idTema,
  flujo_origen: flowName,
  tema_titulo: topic,
  bloque_temporal: bloque,
  timestamp: new Date().toISOString()
};

return $json;

